const allItems = $input.all();
const clusterList = allItems.map(item => item.json);

const briefId = 'BRIEF-' + new Date().toISOString().substring(0, 7).replace('-', '');
const monthEnding = new Date().toISOString().split('T')[0];
const monthLabel = new Date().toLocaleString('en-SG', { month: 'long', year: 'numeric' });

return [{ json: {
  brief_id: briefId,
  month_ending: monthEnding,
  month_label: monthLabel,
  cluster_count: clusterList.length,
  clusters_json: clusterList
} }];
